patch:
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
index 0633388cd411..8c89add3e79d 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
@@ -2750,13 +2750,33 @@ Instruction *InstCombinerImpl::foldSelectOfBools(SelectInst &SI) {
   if (match(CondVal, m_Select(m_Value(A), m_Value(B), m_Zero())) &&
       match(TrueVal, m_Specific(B)) && match(FalseVal, m_Zero()))
     return replaceOperand(SI, 0, A);
+  Value *C;
+  // select c1, c, (select c2, a, b) -> select c2, (select c1, c, a), b
+  //   if c1 = false implies that c2 is true.
+  if (match(FalseVal, m_Select(m_Value(B), m_Value(A), m_Value(C))) &&
+      FalseVal->hasOneUse()) {
+    Optional<bool> Res = isImpliedCondition(CondVal, B, DL, false);
+    if (Res && *Res == true) {
+      Value *NewSel = Builder.CreateSelect(CondVal, TrueVal, A);
+      return SelectInst::Create(B, NewSel, C);
+    }
+  }

+  // select c1, (select c2, a, b), c -> select c2, a, (select c1, b, c)
+  //   if c1 = true implies that c2 is false.
+  if (match(TrueVal, m_Select(m_Value(B), m_Value(A), m_Value(C))) &&
+      TrueVal->hasOneUse()) {
+    Optional<bool> Res = isImpliedCondition(CondVal, B, DL, true);
+    if (Res && *Res == false) {
+      Value *NewSel = Builder.CreateSelect(CondVal, B, FalseVal);
+      return SelectInst::Create(B, A, NewSel);
+    }
+  }
   // ~(A & B) & (A | B) --> A ^ B
   if (match(&SI, m_c_LogicalAnd(m_Not(m_LogicalAnd(m_Value(A), m_Value(B))),
                                 m_c_LogicalOr(m_Deferred(A), m_Deferred(B)))))
     return BinaryOperator::CreateXor(A, B);
-
-  Value *C;
+  // ~(A & B) & (A | B) --> A ^ B
   // select (~a | c), a, b -> and a, (or c, freeze(b))
   if (match(CondVal, m_c_Or(m_Not(m_Specific(TrueVal)), m_Value(C))) &&
       CondVal->hasOneUse()) {
@@ -3130,6 +3150,8 @@ Instruction *InstCombinerImpl::visitSelectInst(SelectInst &SI) {
         replaceOperand(SI, 1, TrueSI->getTrueValue());
         return &SI;
       }
+
+
     }
   }
   if (SelectInst *FalseSI = dyn_cast<SelectInst>(FalseVal)) {
@@ -3147,6 +3169,8 @@ Instruction *InstCombinerImpl::visitSelectInst(SelectInst &SI) {
         replaceOperand(SI, 2, FalseSI->getFalseValue());
         return &SI;
       }
+
+
     }
   }

